import{_ as t,o,c as i,a2 as a}from"./chunks/framework.B72_uj9U.js";const p=JSON.parse('{"title":"Droid — Tool System","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/droid/tool-system.md","filePath":"research/agents/droid/tool-system.md"}'),s={name:"research/agents/droid/tool-system.md"};function r(l,e,n,d,c,u){return o(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="droid-—-tool-system" tabindex="-1">Droid — Tool System <a class="header-anchor" href="#droid-—-tool-system" aria-label="Permalink to &quot;Droid — Tool System&quot;">​</a></h1><blockquote><p>How Droid&#39;s tool system enables autonomous code manipulation, with categories for reading, editing, executing, searching, and extensibility via skills, slash commands, and MCP servers.</p></blockquote><h2 id="core-tool-categories" tabindex="-1">Core Tool Categories <a class="header-anchor" href="#core-tool-categories" aria-label="Permalink to &quot;Core Tool Categories&quot;">​</a></h2><p>Factory Analytics provides visibility into Droid&#39;s tool system by categorizing every tool call. The core categories are:</p><h3 id="read-tools" tabindex="-1">Read Tools <a class="header-anchor" href="#read-tools" aria-label="Permalink to &quot;Read Tools&quot;">​</a></h3><p>File reading and content inspection:</p><ul><li>Read file contents</li><li>Read directory listings</li><li>Read git diffs and history</li><li>Read PR details, review comments, CI status</li></ul><h3 id="edit-tools" tabindex="-1">Edit Tools <a class="header-anchor" href="#edit-tools" aria-label="Permalink to &quot;Edit Tools&quot;">​</a></h3><p>Code and file modification:</p><ul><li>Create new files</li><li>Edit existing files (precise string replacement)</li><li>Delete files</li><li>Batch edits across multiple files</li></ul><h3 id="execute-tools" tabindex="-1">Execute Tools <a class="header-anchor" href="#execute-tools" aria-label="Permalink to &quot;Execute Tools&quot;">​</a></h3><p>Command execution and process management:</p><ul><li>Run shell commands (build, test, lint)</li><li>Execute in sandboxed environments</li><li>Run CI/CD pipelines</li><li>Execute database queries (for analytics)</li></ul><h3 id="grep-tools" tabindex="-1">Grep Tools <a class="header-anchor" href="#grep-tools" aria-label="Permalink to &quot;Grep Tools&quot;">​</a></h3><p>Pattern-based code search:</p><ul><li>Regex search across files</li><li>Content matching with context lines</li><li>File-scoped and project-wide search</li></ul><h3 id="glob-tools" tabindex="-1">Glob Tools <a class="header-anchor" href="#glob-tools" aria-label="Permalink to &quot;Glob Tools&quot;">​</a></h3><p>File discovery by pattern:</p><ul><li>Wildcard pattern matching for file paths</li><li>Directory traversal with pattern filters</li><li>File type filtering</li></ul><h2 id="skills-system" tabindex="-1">Skills System <a class="header-anchor" href="#skills-system" aria-label="Permalink to &quot;Skills System&quot;">​</a></h2><p>Skills are higher-level, reusable capabilities that compose multiple tool calls into domain-specific workflows. From the Analytics data, we know:</p><ul><li><strong>Skills invocations</strong> are tracked as a distinct metric in Factory Analytics.</li><li>Skills represent a level of abstraction above raw tool calls.</li><li>Adoption of skills is considered a &quot;leading indicator of effective usage&quot; per Factory&#39;s documentation.</li></ul><p>Skills likely include patterns like:</p><ul><li><strong>Code review skill</strong>: Read diff → analyze against guidelines → generate structured feedback.</li><li><strong>Migration skill</strong>: Discover patterns → plan changes → apply across files → verify tests pass.</li><li><strong>Incident response skill</strong>: Read error logs → trace to source → propose fix → create PR.</li></ul><h2 id="slash-commands" tabindex="-1">Slash Commands <a class="header-anchor" href="#slash-commands" aria-label="Permalink to &quot;Slash Commands&quot;">​</a></h2><p>Slash commands provide quick access to specific Droid capabilities within interactive sessions:</p><ul><li>Tracked as a distinct adoption metric in Factory Analytics.</li><li>Provide shortcuts for common workflows.</li><li>Similar to the <code>/add</code>, <code>/ask</code>, <code>/code</code> pattern seen in other agents, but specific to Droid&#39;s multi-interface context.</li></ul><h2 id="mcp-server-integration" tabindex="-1">MCP Server Integration <a class="header-anchor" href="#mcp-server-integration" aria-label="Permalink to &quot;MCP Server Integration&quot;">​</a></h2><p>Droid supports <strong>MCP (Model Context Protocol) servers</strong> as an extensibility mechanism:</p><ul><li>Factory Analytics tracks how many users have configured MCP servers.</li><li>MCP servers extend Droid&#39;s tool system with custom capabilities.</li><li>This allows enterprises to add domain-specific tools (internal APIs, proprietary systems, custom databases) without modifying the core agent.</li></ul><h2 id="tool-analytics" tabindex="-1">Tool Analytics <a class="header-anchor" href="#tool-analytics" aria-label="Permalink to &quot;Tool Analytics&quot;">​</a></h2><p>Factory Analytics provides deep visibility into tool usage:</p><h3 id="autonomy-ratio" tabindex="-1">Autonomy Ratio <a class="header-anchor" href="#autonomy-ratio" aria-label="Permalink to &quot;Autonomy Ratio&quot;">​</a></h3><p>The ratio of tool calls to user messages — a key indicator of delegation effectiveness:</p><ul><li><strong>High ratio</strong> (e.g., 13x): Droid is executing complex tasks autonomously.</li><li><strong>Low ratio</strong>: Developers are using Droid more conversationally, providing frequent guidance.</li></ul><h3 id="tool-call-distribution" tabindex="-1">Tool Call Distribution <a class="header-anchor" href="#tool-call-distribution" aria-label="Permalink to &quot;Tool Call Distribution&quot;">​</a></h3><p>Analytics breaks down usage by tool type, revealing:</p><ul><li><strong>Read-heavy</strong> patterns: Teams using Droid for codebase exploration and review.</li><li><strong>Edit-heavy</strong> patterns: Teams using Droid for active code generation and refactoring.</li><li><strong>Execute-heavy</strong> patterns: Teams using Droid for testing and CI/CD workflows.</li></ul><h3 id="platform-feature-adoption" tabindex="-1">Platform Feature Adoption <a class="header-anchor" href="#platform-feature-adoption" aria-label="Permalink to &quot;Platform Feature Adoption&quot;">​</a></h3><p>Analytics tracks adoption of advanced features as leading indicators:</p><table tabindex="0"><thead><tr><th>Feature</th><th>What It Indicates</th></tr></thead><tbody><tr><td>Skills invocations</td><td>Usage of higher-level automation workflows</td></tr><tr><td>Slash commands</td><td>Familiarity with interactive capabilities</td></tr><tr><td>MCP servers configured</td><td>Enterprise extensibility adoption</td></tr><tr><td>Autonomy ratio trend</td><td>Growing trust in agent delegation</td></tr></tbody></table><h2 id="github-actions-integration" tabindex="-1">GitHub Actions Integration <a class="header-anchor" href="#github-actions-integration" aria-label="Permalink to &quot;GitHub Actions Integration&quot;">​</a></h2><p>Droid has specific tooling for CI/CD repair:</p><ul><li><strong><code>github_action_repair</code></strong>: When enabled in <code>.droid.yaml</code>, Droid analyzes GitHub Actions failures and suggests fixes.</li><li>This operates as an automated tool invocation triggered by CI events.</li><li>The repair tool reads failure logs, identifies the root cause, and either comments with a fix or creates a repair PR.</li></ul><h2 id="review-specific-tools" tabindex="-1">Review-Specific Tools <a class="header-anchor" href="#review-specific-tools" aria-label="Permalink to &quot;Review-Specific Tools&quot;">​</a></h2><p>The code review workflow uses specialized tools:</p><ul><li><strong>PR summary generation</strong>: Automatically creates a structured summary of changes.</li><li><strong>File-level summaries</strong>: Per-file change descriptions.</li><li><strong>Guideline matching</strong>: Applies path-specific review rules from <code>.droid.yaml</code>.</li><li><strong>Skip reason commenting</strong>: When review is skipped, explains why (WIP title, excluded label, etc.).</li></ul><h2 id="integration-aware-tools" tabindex="-1">Integration-Aware Tools <a class="header-anchor" href="#integration-aware-tools" aria-label="Permalink to &quot;Integration-Aware Tools&quot;">​</a></h2><p>Droid&#39;s tool system extends beyond code to connected integrations:</p><ul><li><strong>Project management tools</strong>: Read/update Jira tickets, Linear issues, Asana tasks.</li><li><strong>Knowledge tools</strong>: Query Notion, Confluence, Google Drive for relevant documentation.</li><li><strong>Incident tools</strong>: Read Sentry errors, PagerDuty alerts for context during incident response.</li><li><strong>Communication tools</strong>: Send status updates via Slack, Microsoft Teams.</li></ul><p>This integration awareness allows Droid to perform &quot;full-stack&quot; engineering tasks — not just writing code, but understanding the task context, updating project tracking, and communicating results through appropriate channels.</p>',51)])])}const g=t(s,[["render",r]]);export{p as __pageData,g as default};
